import NavBar from "./components/NavBar";
import { useMediaQuery } from 'react-responsive'
import SearchBar from "./components/SearchBar";
import { useState,useEffect } from "react";
import {
  BrowserRouter as Router,
  Switch,
  Route,
} from "react-router-dom";
import requests from "./requests";
import Row from "./components/Row";
import "slick-carousel/slick/slick.css"; 
import "slick-carousel/slick/slick-theme.css";
import AllAbout from "./components/AllAbout";
import { Redirect } from "react-router";
import ALLMovies from "./components/ALLMovies";
import WatchList from './components/WatchList';
import SearchPage from "./components/SearchPage";

function App() {
  const isSmallScreen = useMediaQuery({ query: '(max-width: 563px)' })
  const [allAboutMovie,setAllAboutMovie] = useState({})
  const [movies,setMovies] = useState([])
  const [showSearchMenu,setShowSearchMenu] = useState(false)
  
  const [watchListLen,setWatchListLen] = useState(0)
  const [watchList,SetWatchList] = useState([])
  // here i want to gett watchlist onload
  useEffect(()=>{
    document.title = "Moviea"
    const list = JSON.parse(localStorage.getItem("watchlist"))
    if(list === null){
      localStorage.setItem('watchlist',JSON.stringify([]))
      return
    }else{
      SetWatchList(list)
    }
  },[])

  useEffect(()=>{
    setWatchListLen(watchList.length)
  },[watchList])

  return (
    <div className="App">
      <Router>
        <NavBar  movies={movies} setMovies={setMovies} showSearchMenu={showSearchMenu} setShowSearchMenu={setShowSearchMenu} watchListLen={watchListLen}/>
        {isSmallScreen && 
          <div className="SearchBarHolderWhenOnMobile">
              <SearchBar Class="SearchBar SearchBarOnMobile"  movies={movies} setMovies={setMovies} showSearchMenu={showSearchMenu} setShowSearchMenu={setShowSearchMenu}/>
          </div>
        }
        <Switch>
          <Route path="/search-page" >
            <SearchPage movies={movies}/>
          </Route>
          <Route path="/all-movies">
            <ALLMovies/>
          </Route>
          <Route path="/all-about">
              {allAboutMovie?<AllAbout movie={allAboutMovie} watchList={watchList} setWatchList={SetWatchList} watchListLen={watchListLen} setWatchListLen={setWatchListLen}/>:<Redirect to="/"/>}
          </Route>
          <Route path="/watch-list">
            <WatchList watchList={watchList} SetWatchList={SetWatchList} watchListLen={watchListLen} setWatchListLen={setWatchListLen}/>
          </Route>
          <Route exact path="/">
            <Row title="Trend Now" fetchUrl={requests.fetchTrending} isLarge={true}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Top Rated" fetchUrl={requests.fetchTopRated}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Netflix Originals" fetchUrl={requests.fetchNetflixOriginals}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Action" fetchUrl={requests.fetchActionMovies}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Comedy" fetchUrl={requests.fetchComedyMovies}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Documentaries" fetchUrl={requests.fetchDocumentaries}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Horror" fetchUrl={requests.fetchHorrorMovies}  setAllAboutMovie={setAllAboutMovie}/>
            <Row title="Romance" fetchUrl={requests.fetchRomanceMovies}  setAllAboutMovie={setAllAboutMovie}/>
          </Route>
        </Switch>
      </Router>
      
    </div>
  );
}

export default App;
