import React from 'react'
import requests from '../requests'
import { Link } from 'react-router-dom'


function MovieCard({movie,isLarge}) {
    
    // extract movie infos
    const backdrop_path = requests.image_api+movie.backdrop_path
    const poster_path = requests.image_api+movie.poster_path
    const {id,title,vote_average,} = movie
    return (
        <div className={isLarge?"MovieCardLarge":"MovieCard"}>
            <Link to={{
                pathname:"/all-about",
                state:{
                    movie:movie
                }
            }}>
                <img src={isLarge?backdrop_path:poster_path} alt={title} key={id}/>
            </Link>
            <h4 className="voteAvarage">{vote_average} ⭐</h4>
        </div>
    )
}

export default MovieCard
